export const meta = {
  name: 'ts-restrict-iso-api-scan',
  description: 'Map the Mathlib + project API needed to construct tensorObj_restrict_iso (sheaf-level pullback/tensor/sheafification compatibility + gluing isos of sheaves of modules)',
  phases: [{ title: 'Scan', detail: 'four independent API sweeps' }],
}

const FILE = 'AlgebraicJacobian/Picard/TensorObjSubstrate.lean'

const SCHEMA = {
  type: 'object',
  additionalProperties: false,
  properties: {
    findings: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        properties: {
          name: { type: 'string', description: 'fully-qualified Lean declaration name' },
          signature: { type: 'string', description: 'its type signature (concise)' },
          location: { type: 'string', description: 'Mathlib module or project file' },
          relevance: { type: 'string', description: 'how it could help build tensorObj_restrict_iso' },
        },
        required: ['name', 'signature', 'location', 'relevance'],
      },
    },
    conclusion: { type: 'string', description: 'overall conclusion: is there a usable path, or what is the precise missing ingredient' },
  },
  required: ['findings', 'conclusion'],
}

const TASKS = [
  {
    key: 'restrict-pullback',
    prompt: `In the Lean4 project at AlgebraicJacobian/Picard/, the file AlgebraicJacobian/Picard/TensorObjSubstrate.lean defines \`Scheme.Modules.tensorObj M N := sheafification.obj (PresheafOfModules.Monoidal.tensorObj M.val N.val)\` and uses \`Scheme.Modules.restrict\`, \`Scheme.Modules.pullback\`, \`Scheme.Modules.restrictFunctorIsoPullback\`, \`Scheme.Modules.pullbackComp\`, \`Scheme.Modules.pullbackCongr\`. Find and report the PRECISE definitions/signatures of \`AlgebraicGeometry.Scheme.Modules.restrict\`, \`AlgebraicGeometry.Scheme.Modules.pullback\`, and \`restrictFunctorIsoPullback\` — both in this project (grep AlgebraicJacobian/) and in Mathlib (AlgebraicGeometry.Modules / SheafOfModules). Specifically: is \`Scheme.Modules.pullback f\` for an open immersion \`f\` concretely the sheafification of a presheaf-level pullback, or an inverse-image sheaf functor? Report exact module locations and signatures. Use ripgrep over the project and over the Mathlib source (find it via 'lake env lean --help' or locate .lake/packages/mathlib). Do not edit files.`,
  },
  {
    key: 'sheafify-pullback',
    prompt: `In Mathlib (pinned commit b80f227, locate source under .lake/packages/mathlib/Mathlib), find every lemma/def stating that SHEAFIFICATION commutes with PULLBACK / inverse-image / restriction along a morphism of sites or an open immersion — at the level of \`PresheafOfModules.sheafification\`, \`SheafOfModules\`, presheaves of modules, or general sheaves on a site (\`GrothendieckTopology\`, \`presheafToSheaf\`, \`sheafToPresheaf\`, \`Sheaf.pullback\`, \`Sites.Pullback\`, \`yoneda\`, restriction functors). Report exact names, signatures, module paths. Also: is there ANY API that says the pullback functor on \`SheafOfModules\` is strong/lax monoidal, or commutes with \`PresheafOfModules.Monoidal.tensorObj\`? Search \`PresheafOfModules\`, \`SheafOfModules\`, \`Mathlib.CategoryTheory.Monoidal\`, \`Mathlib.Algebra.Category.ModuleCat.Sheaf\`. Conclude whether a usable "sheafify ∘ pullback ≅ pullback ∘ sheafify" exists. Do not edit files.`,
  },
  {
    key: 'presheaf-tensor-pullback',
    prompt: `In Mathlib (.lake/packages/mathlib/Mathlib), examine \`PresheafOfModules.Monoidal\` (Mathlib.CategoryTheory.Monoidal.PresheafOfModules) and the pullback/restriction functors on \`PresheafOfModules\` (e.g. \`PresheafOfModules.restrictScalars\`, \`PresheafOfModules.pullback\`, restriction along a functor of sites). Is there any lemma that the presheaf-of-modules tensor \`PresheafOfModules.Monoidal.tensorObj\` commutes with restriction-of-scalars / pullback of presheaves — i.e. a sectionwise base-change identity \`B ⊗_A (P ⊗_A Q) ≅ (B ⊗_A P) ⊗_B (B ⊗_A Q)\`? Report exact names and signatures. Also report the full API surface of \`PresheafOfModules.Monoidal\` (what tensorObj/tensorHom/associator/unitor/braiding declarations exist) and whether \`PresheafOfModules.sheafification\` is known to be (op)lax monoidal anywhere. Do not edit files.`,
  },
  {
    key: 'glue-isos',
    prompt: `In the Lean4 project (AlgebraicJacobian/) and Mathlib (.lake/packages/mathlib/Mathlib), find the API for CONSTRUCTING a morphism or isomorphism of \`AlgebraicGeometry.Scheme.Modules X\` (= sheaves of O_X-modules on the small Zariski site) from LOCAL data on an open cover — i.e. sheaf gluing for morphisms/isos: \`Sheaf\` hom being a sheaf, \`SheafOfModules\` hom gluing, equalizer/sheaf-condition for Hom, \`Sheaf.homEquiv\`, \`GrothendieckTopology.Sheaf.isLimit\`, amalgamation of compatible local sections/morphisms. Also report what \`AlgebraicGeometry.Scheme.Modules\` is definitionally (\`SheafOfModules X.ringCatSheaf\`?) and what gluing/local-iso lemmas the project itself already proves (grep for \`IsLocallyTrivial\`, \`restrictIsoUnitOfLE\`, \`restrictFunctorIsoPullback\`, gluing). Conclude whether assembling a GLOBAL associativity/commutativity iso of line bundles from local (per-open) isos is feasible with existing API, and name the precise gluing lemma needed. Do not edit files.`,
  },
]

phase('Scan')
const results = await parallel(TASKS.map(t => () =>
  agent(t.prompt, { label: `scan:${t.key}`, phase: 'Scan', schema: SCHEMA, agentType: 'Explore' })
))

return TASKS.map((t, i) => ({ key: t.key, result: results[i] }))

